<div class="card content-card mb-4"><div class="card-body p-4"><div class="d-flex flex-column flex-md-row justify-content-between align-items-md-center gap-3"><div><h5 class="mb-1">User Access Directory</h5><p class="text-muted mb-0">Manage login accounts, role assignment, and optional employee linkage.</p></div><a href="<?= e(url('/admin/users/create')); ?>" class="btn btn-primary"><i class="bi bi-person-plus me-1"></i>Create User</a></div></div></div>
<div class="card content-card mb-4"><div class="card-body p-4"><form method="get" action="<?= e(url('/admin/users')); ?>" class="row g-3"><div class="col-lg-5"><input type="text" name="q" class="form-control" placeholder="Search username, email, name, or employee..." value="<?= e((string) ($search ?? '')); ?>"></div><div class="col-lg-3"><select name="role_id" class="form-select"><option value="all">All roles</option><?php foreach (($roles ?? []) as $role): ?><option value="<?= e((string) $role['id']); ?>" <?= (string) ($roleId ?? 'all') === (string) $role['id'] ? 'selected' : ''; ?>><?= e((string) $role['name']); ?></option><?php endforeach; ?></select></div><div class="col-lg-2"><select name="status" class="form-select"><?php foreach (['all' => 'All statuses', 'active' => 'Active', 'inactive' => 'Inactive', 'suspended' => 'Suspended'] as $value => $label): ?><option value="<?= e($value); ?>" <?= (string) ($status ?? 'all') === $value ? 'selected' : ''; ?>><?= e($label); ?></option><?php endforeach; ?></select></div><div class="col-lg-2 d-grid"><button type="submit" class="btn btn-outline-secondary">Filter</button></div></form></div></div>
<div class="card content-card"><div class="card-body p-4"><?php if (($users ?? []) === []): ?><div class="empty-state">No user accounts matched the current filters.</div><?php else: ?><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>User</th><th>Role</th><th>Employee Link</th><th>Status</th><th>Password</th><th class="text-end">Action</th></tr></thead><tbody><?php foreach ($users as $user): ?><tr><td><div class="fw-semibold"><?= e(trim((string) (($user['first_name'] ?? '') . ' ' . ($user['last_name'] ?? '')))); ?></div><div class="small text-muted"><?= e((string) $user['username']); ?> • <?= e((string) $user['email']); ?></div></td><td><div><?= e((string) $user['role_name']); ?></div><div class="small text-muted"><?= e((string) $user['role_code']); ?></div></td><td><?php if (!empty($user['employee_id'])): ?><div><?= e((string) ($user['employee_name'] ?? '')); ?></div><div class="small text-muted"><?= e((string) ($user['employee_code'] ?? '')); ?></div><?php else: ?><span class="text-muted">Not linked</span><?php endif; ?></td><td><span class="badge <?= ($user['status'] ?? '') === 'active' ? 'text-bg-success' : (($user['status'] ?? '') === 'suspended' ? 'text-bg-warning' : 'text-bg-secondary'); ?>"><?= e(ucwords((string) $user['status'])); ?></span></td><td><?php if (!empty($user['must_change_password'])): ?><span class="badge text-bg-info">Must change</span><?php else: ?><span class="text-muted">Current</span><?php endif; ?></td><td class="text-end"><a href="<?= e(url('/admin/users/' . $user['id'] . '/edit')); ?>" class="btn btn-sm btn-outline-primary">Edit</a></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></div></div>